&lt;span id=&#34;cb5-19&#34;&gt;&lt;a href=&#34;#cb5-19&#34; aria-hidden=&#34;true&#34; tabindex=&#34;-1&#34;&gt;&lt;/a&gt;      v8 &lt;span class=&#34;op&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;dv&#34;&gt;16&lt;/span&gt;&lt;span class=&#34;er&#34;&gt;i64&lt;/span&gt;&lt;span class=&#34;op&#34;&gt;;&lt;/span&gt;              &lt;span class=&#34;co&#34;&gt;// block size = 16&lt;/span&gt;&lt;/span&gt;
&lt;span id=&#34;cb5-20&#34;&gt;&lt;a href=&#34;#cb5-20&#34; aria-hidden=&#34;true&#34; tabindex=&#34;-1&#34;&gt;&lt;/a&gt;      &lt;span class=&#34;cf&#34;&gt;do&lt;/span&gt;&lt;/span&gt;
&lt;span id=&#34;cb5-21&#34;&gt;&lt;a href=&#34;#cb5-21&#34; aria-hidden=&#34;true&#34; tabindex=&#34;-1&#34;&gt;&lt;/a&gt;      &lt;span class=&#34;op&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;
&lt;span id=&#34;cb5-22&#34;&gt;&lt;a href=&#34;#cb5-22&#34; aria-hidden=&#34;true&#34; tabindex=&#34;-1&#34;&gt;&lt;/a&gt;        result &lt;span class=&#34;op&#34;&gt;=&lt;/span&gt; v3&lt;span class=&#34;op&#34;&gt;[&lt;/span&gt;v5&lt;span class=&#34;op&#34;&gt;];&lt;/span&gt;       &lt;span class=&#34;co&#34;&gt;// 分块将密文解密后的结果和上一块异或&lt;/span&gt;&lt;/span&gt;
&lt;span id=&#34;cb5-23&#34;&gt;&lt;a href=&#34;#cb5-23&#34; aria-hidden=&#34;true&#34; tabindex=&#34;-1&#34;&gt;&lt;/a&gt;        &lt;span class=&#34;op&#34;&gt;*&lt;/span&gt;v3&lt;span class=&#34;op&#34;&gt;++&lt;/span&gt; &lt;span class=&#34;op&#34;&gt;^=&lt;/span&gt; result&lt;span class=&#34;op&#34;&gt;;&lt;/span&gt;       &lt;span class=&#34;co&#34;&gt;// 经典的CBC模式&lt;/span&gt;&lt;/span&gt;
